16: // Client is a gRPC-based Loki client implementation.
17: type Client struct {
18: 	client logproto.PusherClient
19: 	conn   *grpc.ClientConn
20: 	opts   []grpc.DialOption
21: 	cfg    Config
22: }
23: 
24: // NewClient instantiates a new Client.
25: func NewClient(cfg Config, opts ...grpc.DialOption) (*Client, error) {
26: 	w := &Client{
27: 		opts: opts,
28: 		cfg:  cfg,
29: 	}
30: 
31: 	return w, w.init()
32: }
33: 
34: // Write pushes a new request with the given streams through
35: // the attached gRPC connection.
36: func (c *Client) Write(streams []logproto.Stream) (err error) {
37: 	pushRequest := &logproto.PushRequest{
38: 		Streams: streams,
39: 	}
40: 
41: 	ctx, cancel := c.timeoutCtx()
42: 	defer cancel()
43: 
44: 	if len(c.cfg.TenantID) > 0 {
45: 		ctx = injectOrgID(ctx, c.cfg.TenantID)
46: 	}
47: 
48: 	_, err = c.client.Push(ctx, pushRequest)
49: 	return err
50: }
51: 
52: // Close closes the attached gRPC connection.
53: func (c *Client) Close() error {
54: 	return c.conn.Close()
55: }
56: 
57: func (c *Client) init() error {
58: 	if len(c.cfg.URL) == 0 {
59: 		return errors.New("cfg must have Loki url")
60: 	}
61: 
62: 	opts := append(c.opts, c.grpcTLSOption(), c.grpcRetryOption())
63: 	conn, err := grpc.NewClient(c.cfg.URL, opts...)
64: 	if err != nil {
65: 		return err
66: 	}
67: 
68: 	c.conn = conn
69: 	c.client = logproto.NewPusherClient(conn)
70: 	return nil
71: }
72: 
73: func (c *Client) grpcTLSOption() grpc.DialOption {
74: 	if c.cfg.TLSDisabled {
75: 		return grpc.WithTransportCredentials(insecure.NewCredentials())
76: 	}
77: 
78: 	config := &tls.Config{InsecureSkipVerify: false}
79: 	return grpc.WithTransportCredentials(credentials.NewTLS(config))
80: }
81: 
82: func (c *Client) grpcRetryOption() grpc.DialOption {
83: 	return grpc.WithUnaryInterceptor(
84: 		grpcretry.UnaryClientInterceptor(
85: 			grpcretry.WithMax(c.cfg.Retries),
86: 		),
87: 	)
88: }
89: 
90: func (c *Client) timeoutCtx() (context.Context, context.CancelFunc) {
91: 	if c.cfg.Timeout > 0 {
92: 		return context.WithTimeout(context.Background(), c.cfg.Timeout)
93: 	}
94: 
95: 	return context.WithCancel(context.Background())
96: }
